import (
	"fmt"
)

func hammingDistance(x int, y int) int {
	// Step 1: XOR the two integers
	xorResult := x ^ y

	// Step 2: Initialize a counter to zero
	distance := 0

	// Step 3: Iterate through each bit of the result
	for xorResult != 0 {
		// Step 4: If the least significant bit is 1, increment the counter
		if xorResult & 1 == 1 {
			distance++
		}
		// Step 5: Right shift the result to check the next bit
		xorResult >>= 1
	}

	// Step 6: Return the counter as the Hamming distance
	return distance
}

func main() {
	// Test cases
	fmt.Println(hammingDistance(1, 2)) // Output: 2
	fmt.Println(hammingDistance(4, 14)) // Output: 3
	fmt.Println(hammingDistance(0, 0)) // Output: 0
}
