// DecodeNumbers decodes a series of numbers to reveal the hidden pattern which indicates
// the actual values each digit represents. The pattern is defined as follows:
// 0000=4 8888=8 1234=1 5678=3 9012=2 1357=0 2468=4
func DecodeNumbers(dataStr string) int {
	// Define the pattern mapping
	pattern := map[string]int{
		"0000": 4,
		"8888": 8,
		"1234": 1,
		"5678": 3,
		"9012": 2,
		"1357": 0,
		"2468": 4,
	}

	// Initialize the result
	result := 0

	// Iterate through the input string and decode each sequence
	for i := 0; i < len(dataStr); i += 4 {
		// Extract the current sequence of 4 digits
		sequence := dataStr[i : i+4]
		// Decode the sequence using the pattern
		if value, exists := pattern[sequence]; exists {
			result = result * 10 + value
		} else {
			// If the sequence is not found in the pattern, return an error or handle it appropriately
			fmt.Println("Unknown sequence:", sequence)
			return -1
		}
	}

	return result
}

func main() {
